import{_ as o,c as r,o as i,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.50: shell.env Hook, Skills Path Extension, Memory Leak Fix","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.50.md","filePath":"en/changelog/v1.1.50.md","lastUpdated":1772014034000}'),l={name:"en/changelog/v1.1.50.md"};function s(n,t,d,h,c,p){return i(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="v1-1-50-shell-env-hook-skills-path-extension-memory-leak-fix" tabindex="-1">v1.1.50: shell.env Hook, Skills Path Extension, Memory Leak Fix <a class="header-anchor" href="#v1-1-50-shell-env-hook-skills-path-extension-memory-leak-fix" aria-label="Permalink to “v1.1.50: shell.env Hook, Skills Path Extension, Memory Leak Fix”">​</a></h1><p><strong>Release Date</strong>: February 04, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update adds a shell.env Hook for plugins to inject environment variables, Skills system support for reading from <code>.agents/skills</code> directory, fixes AbortController memory leak, and significantly improves desktop experience.</p><hr><h2 id="new-feature-shell-env-hook" tabindex="-1">New Feature: shell.env Hook <a class="header-anchor" href="#new-feature-shell-env-hook" aria-label="Permalink to “New Feature: shell.env Hook”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Added <code>shell.env</code> plugin hook, allowing custom environment variables to be injected into all shell execution contexts.</p><h3 id="what-is-shell-env-hook" tabindex="-1">What is shell.env Hook? <a class="header-anchor" href="#what-is-shell-env-hook" aria-label="Permalink to “What is shell.env Hook?”">​</a></h3><p>This is a plugin event hook that lets you inject environment variables into AI tool calls and user terminals through plugins. For example, you can inject API Keys, project paths, etc., allowing AI to automatically access these variables when executing commands.</p><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3><p>Create a plugin file in your project:</p>',13),e("div",{class:"language-js"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"js"),e("pre",null,[e("code",{"v-pre":""},`// .opencode/plugins/inject-env.js
export const InjectEnvPlugin = async () => {
  return {
    "shell.env": async (input, output) => {
      output.env.MY_API_KEY = "secret"
      output.env.PROJECT_ROOT = input.cwd
    },
  }
}`)])],-1),a('<p>Injected environment variables work for both AI tool execution and user terminal.</p><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/12b-plugins-advanced.html">Plugins Advanced</a></p><hr><h2 id="new-feature-skills-support-agents-skills-directory" tabindex="-1">New Feature: Skills Support .agents/skills Directory <a class="header-anchor" href="#new-feature-skills-support-agents-skills-directory" aria-label="Permalink to “New Feature: Skills Support .agents/skills Directory”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>The Skills system now supports reading SKILL.md files from <code>.agents/skills</code> directory, compatible with more Agent framework directory structures.</p><h3 id="what-s-the-use" tabindex="-1">What&#39;s the Use? <a class="header-anchor" href="#what-s-the-use" aria-label="Permalink to “What&#39;s the Use?”">​</a></h3><p>If you use other Agent frameworks (like Claude Code), you can put Skills in <code>.agents/skills/</code> directory and OpenCode will also recognize them.</p><h3 id="full-search-paths" tabindex="-1">Full Search Paths <a class="header-anchor" href="#full-search-paths" aria-label="Permalink to “Full Search Paths”">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>Path</th></tr></thead><tbody><tr><td>Project-level OpenCode Native</td><td><code>.opencode/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Global OpenCode Native</td><td><code>~/.config/opencode/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Project-level Claude Compatible</td><td><code>.claude/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Global Claude Compatible</td><td><code>~/.claude/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Project-level Agent Compatible</td><td><code>.agents/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Global Agent Compatible</td><td><code>~/.agents/skills/&lt;name&gt;/SKILL.md</code></td></tr></tbody></table><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/03a-skills-basics.html">Skills Basics</a></p><hr><h2 id="new-feature-agent-custom-theme-colors" tabindex="-1">New Feature: Agent Custom Theme Colors <a class="header-anchor" href="#new-feature-agent-custom-theme-colors" aria-label="Permalink to “New Feature: Agent Custom Theme Colors”">​</a></h2><h3 id="what-s-updated-2" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-2" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>You can now set theme colors when customizing Agents, making different Agents easier to distinguish in the interface.</p><hr><h2 id="bug-fix-abortcontroller-memory-leak" tabindex="-1">Bug Fix: AbortController Memory Leak <a class="header-anchor" href="#bug-fix-abortcontroller-memory-leak" aria-label="Permalink to “Bug Fix: AbortController Memory Leak”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When using OpenCode for extended periods, AbortController closures caused memory leaks, occupying more and more memory.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed the AbortController closure memory leak issue. Memory no longer continues to grow during extended use.</p><hr><h2 id="bug-fix-plugin-repeated-installation" tabindex="-1">Bug Fix: Plugin Repeated Installation <a class="header-anchor" href="#bug-fix-plugin-repeated-installation" aria-label="Permalink to “Bug Fix: Plugin Repeated Installation”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Every time OpenCode started, plugins would be reinstalled even if already installed.</p><h3 id="current-status-1" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-1" aria-label="Permalink to “Current Status”">​</a></h3><p>Plugin installation status is correctly cached, no more repeated installations.</p><hr><h2 id="improvement-desktop-experience" tabindex="-1">Improvement: Desktop Experience <a class="header-anchor" href="#improvement-desktop-experience" aria-label="Permalink to “Improvement: Desktop Experience”">​</a></h2><h3 id="session-tab-restore" tabindex="-1">Session Tab Restore <a class="header-anchor" href="#session-tab-restore" aria-label="Permalink to “Session Tab Restore”">​</a></h3><p>Previously opened session tabs are automatically restored after restarting the desktop application.</p><h3 id="command-palette-search" tabindex="-1">Command Palette Search <a class="header-anchor" href="#command-palette-search" aria-label="Permalink to “Command Palette Search”">​</a></h3><p>Session search functionality has been moved to the command palette for more unified operation.</p><h3 id="empty-prompt-submission" tabindex="-1">Empty Prompt Submission <a class="header-anchor" href="#empty-prompt-submission" aria-label="Permalink to “Empty Prompt Submission”">​</a></h3><p>Desktop now allows submitting empty prompts when there are review comments.</p><h3 id="project-edit-icon" tabindex="-1">Project Edit Icon <a class="header-anchor" href="#project-edit-icon" aria-label="Permalink to “Project Edit Icon”">​</a></h3><p>The edit project dialog icon now only shows on hover, making the interface cleaner.</p><hr><h2 id="other-improvements" tabindex="-1">Other Improvements <a class="header-anchor" href="#other-improvements" aria-label="Permalink to “Other Improvements”">​</a></h2><ul><li>TUI added <code>--thinking</code> flag to show reasoning process in run command</li><li>TUI clipboard automatically falls back to native clipboard after OSC52 failure</li><li>CLI <code>run</code> command changed to non-interactive mode</li><li>Gemini schema validation supports nested arrays and non-object types</li><li>Cloudflare AI Gateway now uses official ai-gateway-provider package</li><li>Excluded k2p5 model reasoning variants</li><li>Provider config headers now correctly applied to fetch requests</li></ul><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Experiencing memory leak issues</td><td>✅ Highly Recommended</td></tr><tr><td>Using plugin system</td><td>✅ Recommended</td></tr><tr><td>Desktop users</td><td>✅ Recommended</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',44),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Prevent memory leaks from AbortController closures (@MaxLeiter)</li><li>Revert addition of Trinity model system prompt support</li><li>Add Trinity model system prompt support (@mariamjabara)</li><li>Add shell.env hook for manipulating environment in tools and shell (@tylergannon)</li><li>Use official ai-gateway-provider package for Cloudflare AI Gateway (@elithrar)</li><li>Allow theme colors in agent customization (@IdrisGit)</li><li>Add support for reading skills from .agents/skills directories</li><li>Provider headers from config not applied to fetch requests (@cloudyan)</li><li>Ensure MCP tools are sanitized</li><li>Add .slnx to C#/F# LSP root detection (@workedbeforepush)</li><li>Improve skills system with better prompting, fix permission requests after skill invocation, and ensure agents can locate scripts and resources</li><li>Exclude k2p5 from reasoning variants (@neavo)</li><li>Handle nested array items for Gemini schema validation (@mugnimaestra)</li><li>Plugins are always reinstalled (@neriousy)</li><li>Strip properties and required fields from non-object types in Gemini schema (@ChickenBreast-ky)</li><li>Make CLI run command non-interactive</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add --thinking flag to show reasoning blocks in run command</li><li>Always fall back to native clipboard after OSC52 (@MartinWie)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Faster end-to-end tests (@neriousy)</li><li>Update command palette placeholder text</li><li>Model selector truncating too soon</li><li>Improve spacing in application UI</li><li>Allow empty prompt with review comments in desktop (@dbpolito)</li><li>Fixed terminal serialization bug in app</li><li>Don&#39;t force mount tooltips in the app</li><li>Restore previously opened session tabs on app restart (@ProdigyRahul)</li><li>Edit project dialog icon now shows on hover (@ProdigyRahul)</li><li>Move session search to command palette</li><li>Fix custom providers overflow in app (@DNGriffin)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=o(l,[["render",s]]);export{u as __pageData,g as default};
